const b = $json.body ?? $json;
const text = String(b.text || '').trim();
if (!text) throw new Error('text 필요');

const now = new Date();
const thisYear = now.getUTCFullYear();

const pad = (n) => String(n).padStart(2, '0');
const fmtKST = (utcMs) => {
  const d = new Date(utcMs + 9 * 60 * 60 * 1000);
  return `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())}T${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:00+09:00`;
};

const rangeRe = /(?:(\d{4})년\s*)?(\d{1,2})월\s*(\d{1,2})일\s*부터\s*(?:(\d{4})년\s*)?(\d{1,2})월\s*(\d{1,2})일\s*까지\s*(.+)/;
const rm = text.match(rangeRe);
if (rm) {
  const sy = rm[1] ? Number(rm[1]) : thisYear;
  const sm = Number(rm[2]);
  const sd = Number(rm[3]);
  const ey = rm[4] ? Number(rm[4]) : sy;
  const em = Number(rm[5]);
  const ed = Number(rm[6]);
  const title = rm[7].trim().replace(/^에\s*/, '');

  const startUtcMs = Date.UTC(sy, sm - 1, sd, -9, 0, 0);
  const endExclusiveUtcMs = Date.UTC(ey, em - 1, ed + 1, -9, 0, 0);

  return [{ title, start: fmtKST(startUtcMs), end: fmtKST(endExclusiveUtcMs), timezone: 'Asia/Seoul', allDay: true, original: text }];
}

const singleRe = /(?:(\d{4})년\s*)?(\d{1,2})월\s*(\d{1,2})일\s*(오전|오후|아침|점심|저녁|밤)?\s*(\d{1,2})시(?:\s*(\d{1,2})분?)?\s*(.+)/;
const m = text.match(singleRe);
if (!m) throw new Error('형식 예: 2월 20일 저녁 7시 30분 테스트 일정 / 2월 23일부터 2월 26일까지 대만 여행');

const year = m[1] ? Number(m[1]) : thisYear;
const month = Number(m[2]);
const day = Number(m[3]);
const period = m[4] || '';
let hour = Number(m[5]);
const minute = m[6] ? Number(m[6]) : 0;
const title = m[7].trim().replace(/^에\s*/, '');

if (['오후', '저녁', '밤'].includes(period) && hour < 12) hour += 12;
if (['오전', '아침'].includes(period) && hour === 12) hour = 0;
if (period === '점심' && hour < 12) hour += 12;

const startUtcMs = Date.UTC(year, month - 1, day, hour - 9, minute, 0);
const endUtcMs = startUtcMs + 30 * 60 * 1000;

return [{ title, start: fmtKST(startUtcMs), end: fmtKST(endUtcMs), timezone: 'Asia/Seoul', allDay: false, original: text }];

